import os
import re
import numpy as np
import pandas as pd
import networkx as nx
import os
import re
import numpy as np
import pandas as pd
# -*- coding: utf-8 -*-
"""
compute_F_factor.py
-------------------
Compute the spine-area correction factor F for a population of pyramidal
neurons reconstructed in the H01 EM dataset.

F is defined per Eyal et al. (2016) / Holmes & Rall (1992) as:

        A_shaft + A_spines
   F = --------------------
            A_shaft

where surface areas are computed as the lateral surface of the frustum
(truncated cone) connecting each tree node to its parent:

   A_segment = pi * (r1 + r2) * sqrt( (r1 - r2)^2 + L^2 )

Following Eyal (2016/2018), the correction is applied only to dendritic
segments whose path-distance from the soma exceeds 60 um. Proximal
segments (<= 60 um) are excluded from BOTH numerator and denominator,
so they contribute neither shaft nor spine area to F.

This module relies on `label_dendritic_spines_robust` (provided in the
project) to attach spine labels to each neuron's CSV. Coordinates and
radii in the source CSVs are in NANOMETRES; the function therefore
expresses the soma cutoff internally in nm.
"""

import os
import re
import pickle
import numpy as np
import pandas as pd
from collections import defaultdict

# label_dendritic_spines_robust is defined in morpholgy_pathways.py
# from morpholgy_pathways import label_dendritic_spines_robust


# --------------------------------------------------------------------------- #
#  Geometry helpers                                                           #
# --------------------------------------------------------------------------- #

def _frustum_lateral_area(r1, r2, length):
    """Lateral surface of a truncated cone with end radii r1, r2 and slant
    height computed from `length` (axial distance between end-faces)."""
    slant = np.sqrt((r1 - r2) ** 2 + length ** 2)
    return np.pi * (r1 + r2) * slant


# --------------------------------------------------------------------------- #
#  Per-neuron F                                                               #
# --------------------------------------------------------------------------- #

def _compute_F_for_neuron(df,
                          soma_cutoff_nm=60_000.0,
                          shaft_regex=r'dendrite|apical|^1$',
                          spine_labels=('spine', 'head', 'neck'),
                          distance_bins_nm=None,
                          default_radius_nm=50.0):
    """
    Compute F for a single neuron given its labelled morphology DataFrame.

    Parameters
    ----------
    df : pandas.DataFrame
        Must contain columns ['id', 'p', 'x', 'y', 'z', 'annotated_type'].
        Optionally 'r' (radius in nm); falls back to `default_radius_nm`.
    soma_cutoff_nm : float
        Path-distance from soma below which segments are excluded from F.
    shaft_regex : str
        Regex matching annotated_type strings classified as dendritic shaft.
    spine_labels : tuple of str
        Annotated_type values classified as belonging to spines (head, neck,
        or generic 'spine').
    distance_bins_nm : list of float or None
        If provided, also compute F per path-distance bin (lower edges).
        Bins extend [edge_i, edge_{i+1}); the last bin extends to +inf.
    default_radius_nm : float
        Fallback radius (nm) when 'r' column is missing.

    Returns
    -------
    dict with keys:
        'F'                 : global F factor (float)
        'A_shaft'           : total dendritic shaft area beyond cutoff (nm^2)
        'A_spines'          : total spine area beyond cutoff (nm^2)
        'n_spine_segments'  : count of spine segments included
        'n_shaft_segments'  : count of shaft segments included
        'F_by_bin'          : dict {bin_edge_nm: F} (only if distance_bins_nm)
    """
    work = df.copy()
    if 'r' not in work.columns:
        work['r'] = default_radius_nm

    # ----- Build parent->child topology and node lookup ----------------- #
    node = work.set_index('id')[['p', 'x', 'y', 'z', 'r', 'annotated_type']
                                ].to_dict('index')

    # Identify the soma root (p == -1). If multiple, use the first.
    roots = work[work['p'] == -1]['id'].values
    if len(roots) == 0:
        raise ValueError("No root node (p == -1) found in this neuron.")
    soma_id = roots[0]

    # ----- Compute path distance from soma for every node --------------- #
    # BFS from the soma along the parent-child tree.
    children_map = defaultdict(list)
    for nid_, attrs in node.items():
        if attrs['p'] != -1:
            children_map[attrs['p']].append(nid_)

    path_dist = {soma_id: 0.0}
    stack = [soma_id]
    while stack:
        parent = stack.pop()
        p_attrs = node[parent]
        p_xyz = np.array([p_attrs['x'], p_attrs['y'], p_attrs['z']])
        for child in children_map[parent]:
            c_attrs = node[child]
            c_xyz = np.array([c_attrs['x'], c_attrs['y'], c_attrs['z']])
            seg_len = np.linalg.norm(c_xyz - p_xyz)
            path_dist[child] = path_dist[parent] + seg_len
            stack.append(child)

    # ----- Pre-compile classifiers -------------------------------------- #
    shaft_re = re.compile(shaft_regex, re.IGNORECASE)
    spine_set = {s.lower() for s in spine_labels}

    def _is_shaft(label):
        return bool(shaft_re.search(str(label)))

    def _is_spine(label):
        return str(label).lower() in spine_set

    # ----- Accumulate areas --------------------------------------------- #
    A_shaft_total = 0.0
    A_spine_total = 0.0
    n_shaft_seg = 0
    n_spine_seg = 0

    # If binning requested, prepare per-bin accumulators
    if distance_bins_nm is not None:
        bin_edges = sorted(distance_bins_nm)
        bin_shaft = {edge: 0.0 for edge in bin_edges}
        bin_spine = {edge: 0.0 for edge in bin_edges}

    for child_id, c_attrs in node.items():
        parent_id = c_attrs['p']
        if parent_id == -1:
            continue            # soma has no incoming segment

        c_label = c_attrs['annotated_type']
        is_spine = _is_spine(c_label)
        is_shaft = _is_shaft(c_label)
        if not (is_spine or is_shaft):
            continue            # axon / soma / unclassified -> ignore

        # Spine area must be paired with a shaft, so we keep its area
        # only if its path-distance from soma exceeds the cutoff.
        d = path_dist.get(child_id, np.inf)
        if d <= soma_cutoff_nm:
            continue

        p_attrs = node[parent_id]
        p_xyz = np.array([p_attrs['x'], p_attrs['y'], p_attrs['z']])
        c_xyz = np.array([c_attrs['x'], c_attrs['y'], c_attrs['z']])
        seg_len = np.linalg.norm(c_xyz - p_xyz)
        if seg_len <= 0.0:
            continue

        r1 = float(p_attrs['r'])
        r2 = float(c_attrs['r'])
        area = _frustum_lateral_area(r1, r2, seg_len)

        if is_shaft:
            A_shaft_total += area
            n_shaft_seg += 1
        else:                                   # is_spine
            A_spine_total += area
            n_spine_seg += 1

        if distance_bins_nm is not None:
            # Find bin: largest edge <= d
            idx = np.searchsorted(bin_edges, d, side='right') - 1
            if idx >= 0:
                edge = bin_edges[idx]
                if is_shaft:
                    bin_shaft[edge] += area
                else:
                    bin_spine[edge] += area

    # ----- F factor ----------------------------------------------------- #
    if A_shaft_total == 0.0:
        F = np.nan
    else:
        F = (A_shaft_total + A_spine_total) / A_shaft_total

    out = {
        'F': F,
        'A_shaft': A_shaft_total,
        'A_spines': A_spine_total,
        'n_shaft_segments': n_shaft_seg,
        'n_spine_segments': n_spine_seg,
    }

    if distance_bins_nm is not None:
        F_by_bin = {}
        for edge in bin_edges:
            denom = bin_shaft[edge]
            F_by_bin[edge] = (denom + bin_spine[edge]) / denom if denom > 0 \
                else np.nan
        out['F_by_bin'] = F_by_bin

    return out


# --------------------------------------------------------------------------- #
#  Population entry point                                                     #
# --------------------------------------------------------------------------- #

def compute_F_factors(target_ids,
                      output_path,
                      output_filename='F_factors',
                      input_dir='/content/drive/MyDrive/Colab Notebooks/'
                                'Reconstructed neurons',
                      spine_length_threshold_nm=5000.0,
                      use_robust_head_neck=True,
                      soma_cutoff_nm=60_000.0,
                      distance_bins_nm=None,
                      verbose=True):
    """
    For each neuron in `target_ids`:
        1. Load its CSV from `input_dir` (via label_dendritic_spines_robust),
           which also labels dendritic spine nodes.
        2. Compute F = (A_shaft + A_spines) / A_shaft over dendritic
           segments whose path-distance from the soma exceeds
           `soma_cutoff_nm` (default 60 um).
    Then aggregate the per-neuron F values into population mean and SD,
    and persist everything (per-cell + statistics) to disk.

    Parameters
    ----------
    target_ids : list of int
        Neuron IDs (e.g. all pyramidal cells of one cortical layer).
    output_path : str
        Directory in which to save the results.
    output_filename : str
        Base name (no extension) for the saved files. Use this to
        differentiate between layers, e.g. 'F_factors_L4_pyr'.
    input_dir : str
        Directory containing 'neuron_<id>.csv' files.
    spine_length_threshold_nm : float
        Threshold passed to label_dendritic_spines_robust (subtree length
        below which a dendritic side-branch is reclassified as a spine).
    use_robust_head_neck : bool
        If True (default), use the head/neck-aware version of
        label_dendritic_spines_robust (spine_labels = head, neck, spine).
        If False, the simple-spine version is used.
    soma_cutoff_nm : float
        Proximal cutoff (default 60_000 nm = 60 um), per Eyal et al. 2016.
    distance_bins_nm : list of float or None
        Optional bin edges (nm) for distance-binned F profile.
        E.g. [60_000, 200_000, 400_000] gives three bins:
          [60-200), [200-400), [400+) um from soma.
    verbose : bool

    Returns
    -------
    pandas.DataFrame indexed by neuron id, with columns:
        F, A_shaft, A_spines, n_shaft_segments, n_spine_segments
    Also persists:
        <output_path>/<output_filename>.csv   per-cell table
        <output_path>/<output_filename>.pkl   full results incl. stats
                                              and (if requested) bin profiles
    """
    # Late import so the module is importable in environments that don't
    # have google.colab installed.
    #from morpholgy_pathways import label_dendritic_spines_robust

    os.makedirs(output_path, exist_ok=True)

    # ------------------------------------------------------------------- #
    # 1. Load and label every neuron in one batch call                    #
    # ------------------------------------------------------------------- #
    if verbose:
        print(f"📥 Loading and labelling {len(target_ids)} neurons "
              f"from {input_dir} ...")
    neuron_dict = label_dendritic_spines_robust(
        target_ids,
        input_dir=input_dir,
        spine_length_threshold_nm=spine_length_threshold_nm,
    )

    # The robust head/neck variant emits 'head' and 'neck' labels;
    # the simple variant emits 'spine'. We accept all three.
    if use_robust_head_neck:
        spine_labels = ('spine', 'head', 'neck')
    else:
        spine_labels = ('spine',)

    # ------------------------------------------------------------------- #
    # 2. Compute F per neuron                                             #
    # ------------------------------------------------------------------- #
    per_cell = {}
    for nid in target_ids:
        if nid not in neuron_dict:
            if verbose:
                print(f"⚠️  Neuron {nid}: no labelled DataFrame returned. "
                      f"Skipping.")
            continue
        try:
            res = _compute_F_for_neuron(
                neuron_dict[nid],
                soma_cutoff_nm=soma_cutoff_nm,
                spine_labels=spine_labels,
                distance_bins_nm=distance_bins_nm,
            )
        except Exception as e:
            if verbose:
                print(f"⚠️  Neuron {nid}: F computation failed ({e}). "
                      f"Skipping.")
            continue
        per_cell[nid] = res
        if verbose:
            extra = ''
            if distance_bins_nm is not None:
                extra = '  | bins: ' + ', '.join(
                    f'{e/1000:.0f}um→{v:.2f}'
                    for e, v in res['F_by_bin'].items()
                )
            print(f"   • neuron {nid}: F = {res['F']:.3f}  "
                  f"(shaft={res['n_shaft_segments']}, "
                  f"spines={res['n_spine_segments']}){extra}")

    # ------------------------------------------------------------------- #
    # 3. Aggregate                                                        #
    # ------------------------------------------------------------------- #
    df_out = pd.DataFrame.from_dict(per_cell, orient='index')
    df_out.index.name = 'neuron_id'

    F_values = df_out['F'].dropna().values
    if len(F_values) == 0:
        F_mean, F_std, F_sem, F_n = np.nan, np.nan, np.nan, 0
    else:
        F_mean = float(np.mean(F_values))
        F_std = float(np.std(F_values, ddof=1)) if len(F_values) > 1 \
            else 0.0
        F_sem = F_std / np.sqrt(len(F_values)) if len(F_values) > 1 \
            else 0.0
        F_n = int(len(F_values))

    summary = {
        'F_mean': F_mean,
        'F_std': F_std,
        'F_sem': F_sem,
        'n_cells': F_n,
        'n_cells_requested': len(target_ids),
        'soma_cutoff_nm': soma_cutoff_nm,
        'spine_length_threshold_nm': spine_length_threshold_nm,
        'spine_labels_used': spine_labels,
    }

    if distance_bins_nm is not None:
        # Per-bin aggregation across cells
        bin_edges = sorted(distance_bins_nm)
        bin_summary = {}
        for edge in bin_edges:
            vals = np.array([
                d['F_by_bin'][edge]
                for d in per_cell.values()
                if not np.isnan(d['F_by_bin'][edge])
            ])
            if len(vals) == 0:
                bin_summary[edge] = {'mean': np.nan, 'std': np.nan,
                                     'n': 0}
            else:
                bin_summary[edge] = {
                    'mean': float(np.mean(vals)),
                    'std': float(np.std(vals, ddof=1)) if len(vals) > 1
                    else 0.0,
                    'n': int(len(vals)),
                }
        summary['F_by_bin'] = bin_summary

    # ------------------------------------------------------------------- #
    # 4. Persist                                                          #
    # ------------------------------------------------------------------- #
    csv_path = os.path.join(output_path, f"{output_filename}.csv")
    pkl_path = os.path.join(output_path, f"{output_filename}.pkl")

    # CSV: per-cell table + summary appended as comments / extra rows
    df_out.to_csv(csv_path)

    # Pickle: complete object with per-cell results and summary
    with open(pkl_path, 'wb') as f:
        pickle.dump({'per_cell': per_cell,
                     'summary': summary,
                     'per_cell_table': df_out}, f)

    if verbose:
        print(f"\n✅ Population F (n={F_n}/{len(target_ids)}): "
              f"{F_mean:.3f} ± {F_std:.3f} (mean ± SD)")
        print(f"   Saved per-cell table  → {csv_path}")
        print(f"   Saved full results    → {pkl_path}")

    return df_out, summary


# --------------------------------------------------------------------------- #
#  End of module                                                              #
# --------------------------------------------------------------------------- #


def label_dendritic_spines_robust(neuron_ids, input_dir='/content/drive/MyDrive/Colab Notebooks/Reconstructed neurons', output_dir=None, spine_length_threshold_nm=3000.0):
    """
    Identifies dendritic spines by evaluating entire terminal subtrees.
    This safely handles bifurcating spines and reconstruction artifacts
    by summing the total length of all branches stemming from a main arbor.
    """
    updated_neurons = {}

    print(f"🔍 Searching for complex dendritic spines across {len(neuron_ids)} neurons (Threshold: {spine_length_threshold_nm} nm)...")

    for nid in neuron_ids:
        filepath = os.path.join(input_dir, f"neuron_{nid}.csv")

        if not os.path.exists(filepath):
            print(f"⚠️ File for neuron {nid} not found. Skipping.")
            continue

        df = pd.read_csv(filepath)

        if not {'id', 'p', 'x', 'y', 'z', 'annotated_type'}.issubset(df.columns):
            print(f"⚠️ Missing required columns in neuron {nid}. Skipping.")
            continue

        # 1. Build a Directed Graph
        G = nx.DiGraph()
        G.add_nodes_from(df['id'])
        # Only add valid edges (exclude the root node's parent placeholder)
        valid_edges = df[df['p'] != -1][['p', 'id']].values
        G.add_edges_from(valid_edges)

        node_coords = df.set_index('id')[['x', 'y', 'z']].to_dict('index')
        node_types = df.set_index('id')['annotated_type'].to_dict()

        spine_nodes = set()

        # 2. Identify all branch points in the neuron
        branch_points = [n for n in G.nodes() if G.out_degree(n) > 1]

        # 3. Evaluate the subtrees attached to each branch point
        for bp in branch_points:
            # Ensure the branch point is on a dendrite/apical section
            parent_type = str(node_types.get(bp, ''))
            if not re.search(r'dendrite|apical|^1$', parent_type, re.IGNORECASE):
                continue

            # Look at every branch sprouting from this branch point
            for child in G.successors(bp):
                # Isolate the entire subtree (the child and all its descendants)
                try:
                    subtree_nodes = nx.descendants(G, child)
                    subtree_nodes.add(child)
                except nx.NetworkXError:
                    continue

                # 4. Calculate the total cable length of this entire subtree
                total_subtree_length = 0.0
                for node in subtree_nodes:
                    # In a tree, every node (except root) has exactly 1 parent
                    parent = list(G.predecessors(node))[0]

                    p1 = np.array([node_coords[node]['x'], node_coords[node]['y'], node_coords[node]['z']])
                    p2 = np.array([node_coords[parent]['x'], node_coords[parent]['y'], node_coords[parent]['z']])

                    total_subtree_length += np.linalg.norm(p1 - p2)

                # 5. If the total sum of all branches is below threshold, it's a spine complex
                if 0 < total_subtree_length <= spine_length_threshold_nm:
                    spine_nodes.update(subtree_nodes)

        # 6. Apply labels and save
        if spine_nodes:
            df.loc[df['id'].isin(spine_nodes), 'annotated_type'] = 'spine'

        updated_neurons[nid] = df
        print(f"✅ Neuron {nid}: Identified and relabeled {len(spine_nodes)} spine nodes (including bifurcations).")

        if output_dir:
            os.makedirs(output_dir, exist_ok=True)
            out_filepath = os.path.join(output_dir, f"neuron_{nid}_spines.csv")
            df.to_csv(out_filepath, index=False)

    return updated_neurons

